887	// ErrClosureGateRejected indicates a close was refused because the bead does
888	// not carry the evidence required for an automated closure: a terminal
889	// verdict event (review APPROVE with non-empty rationale, or an explicit
890	// review-skipped / manual-close marker) AND an execution-evidence marker
891	// (closing_commit_sha, session_id, or an execute-bead success event in the
892	// events history).
893	//
894	// Automated execute-loop paths (execute-bead + reviewer) always go through
895	// CloseWithEvidence. The plain Store.Close remains as the manual
896	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
897	// acceptance §1).
898	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
899	
900	// ClosureGate inspects a bead and returns nil iff the close is safe. It
901	// rejects only the specific shapes that caused the 2026-04-18/20
902	// review-malfunction incidents:
903	//
904	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
905	//     closing_commit_sha. Rejected by the execution-evidence check —
906	//     closing_commit_sha must be non-empty OR at least one event must exist.
907	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
908	//     body is empty. Rejected — APPROVE with no rationale is exactly the
909	//     parse-mis-extract shape the reviewer bug produced.
910	//
911	// Beads without a review step (--no-review, no Reviewer configured, already-
912	// satisfied paths) pass the gate as long as they carry execution evidence.
913	// This keeps the surface small: the gate catches known-bad shapes, not every
914	// conceivable edge case. Additional invariants belong in future dedicated
915	// beads so the rejection reason stays auditable.
916	func ClosureGate(b *Bead) error {
917		if b == nil {
918			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
919		}
920		hasClosingCommit := false
921		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
922			hasClosingCommit = true
923		}
924		events := decodeBeadEvents(b.Extra["events"])
925		// Reject the axon-c5cc071a shape: no events AND no closing commit.
926		if len(events) == 0 && !hasClosingCommit {
927			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
928		}
929		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
930		for _, e := range events {
931			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
932				if strings.TrimSpace(e.Body) == "" {
933					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
934				}
935			}
936		}
937		return nil
938	}
