139	func (s *Store) mergeJSONL(data string) (int, error) {
140		var incoming []Bead
141		var parseErrors int
142	
143		// Try as JSON array first, then as JSONL
144		trimmed := strings.TrimSpace(data)
145		if strings.HasPrefix(trimmed, "[") {
146			var raw []json.RawMessage
147			if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
148				return 0, fmt.Errorf("bead: import parse: %w", err)
149			}
150			for _, r := range raw {
151				b, err := unmarshalBead(r)
152				if err != nil {
153					parseErrors++
154					continue
155				}
156				incoming = append(incoming, b)
157			}
158		} else {
159			for _, line := range strings.Split(trimmed, "\n") {
160				line = strings.TrimSpace(line)
161				if line == "" {
162					continue
163				}
164				b, err := unmarshalBead([]byte(line))
165				if err != nil {
166					parseErrors++
167					continue
168				}
169				incoming = append(incoming, b)
170			}
171		}
172	
173		if parseErrors > 0 && len(incoming) == 0 {
174			return 0, fmt.Errorf("bead: import failed: %d malformed record(s), 0 valid", parseErrors)
175		}
176		if parseErrors > 0 {
177			fmt.Fprintf(os.Stderr, "bead: import: skipped %d malformed record(s)\n", parseErrors)
178		}
179	
180		if len(incoming) == 0 {
181			return 0, nil
182		}
183	
184		return s.mergeBeads(incoming)
185	}
186	
187	func (s *Store) mergeBeads(incoming []Bead) (int, error) {
188		var count int
189		err := s.WithLock(func() error {
190			existing, err := s.ReadAll()
191			if err != nil {
192				return err
193			}
194	
195			existingIDs := make(map[string]bool)
196			for _, b := range existing {
197				existingIDs[b.ID] = true
198			}
199	
200			// Collect IDs from incoming for cross-reference validation
201			incomingIDs := make(map[string]bool)
202			for _, b := range incoming {
203				incomingIDs[b.ID] = true
204			}
205	
206			for _, b := range incoming {
207				if existingIDs[b.ID] {
208					continue // skip duplicates
209				}
210				// Normalize: ensure valid status
211				if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed {
212					b.Status = StatusOpen
213				}
214				// Clamp priority
215				if b.Priority < MinPriority {
216					b.Priority = MinPriority
217				}
218				if b.Priority > MaxPriority {
219					b.Priority = MaxPriority
220				}
221				// Validate deps exist in either existing or incoming set
222				for _, depID := range b.DepIDs() {
223					if !existingIDs[depID] && !incomingIDs[depID] {
224						fmt.Fprintf(os.Stderr, "bead: import: %s has dangling dep %s (skipped)\n", b.ID, depID)
225					}
226				}
227				existing = append(existing, b)
228				existingIDs[b.ID] = true
229				count++
230			}
231	
232			// Validate no circular dependencies in merged set
233			depMap := make(map[string][]string)
234			for _, b := range existing {
235				depMap[b.ID] = b.DepIDs()
236			}
237			for _, b := range existing {
238				if len(b.Dependencies) > 0 && hasCycle(depMap, b.ID) {
239					return fmt.Errorf("bead: import would create circular dependency involving %s", b.ID)
240				}
241			}
242	
243			return s.WriteAll(existing)
244		})
245		return count, err
246	}
