505			for i := range beads {
506				if beads[i].ID == id {
507					mutate(&beads[i])
508					beads[i].UpdatedAt = time.Now().UTC()
509					// Core validation after mutation
510					if err := s.validateBead(&beads[i]); err != nil {
511						return err
512					}
513					// Run update hook
514					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
515						return err
516					}
517					found = true
518					break
519				}
520			}
